  eventBridgeServerPixelUpdate(arn: "arn:aws:events:us-east-1:123456789012:event-bus/local") {
    serverPixel {
      id
      status
      webhookEndpointAddress
    }
    userErrors {
      field
      message
    }
  }
  pubSubServerPixelUpdate(pubSubProject: "local-project", pubSubTopic: "local-topic") {
    serverPixel {
      id
      status
      webhookEndpointAddress
    }
    userErrors {
      field
      message
    }
